import java.util.ArrayDeque

fun solve(weight: Array<Long>): Long {
    val n = weight.size
    if (n == 0) return 0L

    val prevGreater = LongArray(n) { -1L }
    val stack = ArrayDeque<Int>()

    for (i in 0 until n) {
        while (stack.isNotEmpty() && weight[stack.last()] <= weight[i]) {
            stack.pop()
        }
        if (stack.isNotEmpty()) {
            prevGreater[i] = stack.last().toLong()
        } else {
            prevGreater[i] = -1L
        }
        stack.push(i)
    }

    val dp = LongArray(n)
    dp[0] = 0L

    for (i in 1 until n) {
        if (prevGreater[i] != -1L) {
            val j = prevGreater[i].toInt()
            if (j == 0) {
                dp[i] = max(dp[i - 1], 0L + 1)
            } else {
                dp[i] = max(dp[i - 1], dp[j - 1] + 1)
            }
        } else {
            dp[i] = dp[i - 1]
        }
    }

    return dp[n - 1]
}
